// Google Ads API v19 REST — réponse en camelCase, montants en micros
// 1 micro = 0,000001 euro → diviser par 1_000_000
const results = $input.first().json.results || [];

if (results.length === 0) {
  return [{ json: { campagnes: [] } }];
}

const campagnes = results.map(r => ({
  campagne: r.campaign?.name ?? 'N/A',
  client:   r.customer?.descriptiveName ?? 'N/A',
  budget:   Math.round((parseInt(r.campaignBudget?.amountMicros ?? '0') / 1_000_000) * 100) / 100,
  depense:  Math.round((parseInt(r.metrics?.costMicros ?? '0')        / 1_000_000) * 100) / 100,
  compte:   'Compte #' + (r.campaign?.id ?? 'N/A')
}));

return [{ json: { campagnes } }];

const seuil = $('⚙️ Config').item.json.seuil_alerte_pct;
const campagnes = $input.item.json.campagnes;
const heure = new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
const date  = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' });
const heureActuelle = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' })).getHours();

function genererRecommandation(c, hActuelle) {
  const burnRate = hActuelle > 0 ? c.depense / hActuelle : c.depense / 20;
  const heuresRestantes = burnRate > 0 ? c.reste / burnRate : 99;
  const heureEpuisement = hActuelle + heuresRestantes;
  if (c.pct >= 95) return 'Pause immédiate recommandée — budget quasi épuisé.';
  if (heureEpuisement <= 24) {
    const h = Math.floor(heureEpuisement);
    const m = Math.round((heureEpuisement - h) * 60);
    return `Budget épuisé estimé à ${h}h${m > 9 ? m : '0' + m}. Action : réduire enchères -20% ou pauser.`;
  }
  return 'Surveiller — rythme actuel OK mais à surveiller en fin de journée.';
}

const alertes = campagnes
  .map(c => ({
    ...c,
    pct:  Math.round((c.depense / c.budget) * 100),
    reste: Math.round((c.budget - c.depense) * 100) / 100
  }))
  .map(c => ({ ...c, recommandation: genererRecommandation(c, heureActuelle) }))
  .filter(c => c.pct >= seuil)
  .sort((a, b) => b.pct - a.pct);

return [{ json: { alertes, total: alertes.length, heure, date, seuil } }];

const { alertes, heure, date, seuil } = $input.item.json;
const agence = $('⚙️ Config').item.json.nom_agence;

const lignes = alertes.map(a => {
  const emoji = a.pct >= 95 ? '🔴' : a.pct >= 85 ? '🟠' : '🟡';
  return [
    `${emoji} *${a.campagne}* — ${a.client}`,
    `Budget : ${a.budget}€  ·  Dépensé : *${a.depense}€*  ·  *${a.pct}%* utilisé  ·  Reste : ${a.reste}€`,
    `_${a.compte}_`,
    `💡 ${a.recommandation}`,
    `─────────────────────`
  ].join('\n');
}).join('\n\n');

const message = [
  `🚨 *ALERTE BUDGET GOOGLE ADS*`,
  `📅 ${date} à ${heure}`,
  `🏢 ${agence}  ·  Seuil : ${seuil}%`,
  `─────────────────────`,
  '',
  lignes,
  '',
  `⚡ *${alertes.length} campagne(s) à risque*`,
  `Vérifiez vos budgets avant épuisement total.`
].join('\n');

return [{ json: { message, nb_alertes: alertes.length } }];
